@spec vm_insert_delete_row_lane_spec  src=tests/specs/vm_insert_delete_row_lane_spec.lua  loc=106  sha=6fb5e8f  cases=3
@exercises trackerView (h.vm), editCursor (h.ec), commandManager (h.cmgr), trackerManager (h.tm)
@surface   vm:setGridSize, ec:setPos, cmgr:invoke, tm:getChannel
@harness   mk{seed.notes}

# Intent
  insertRow/deleteRow across the open-tail sentinel: `shiftPlan` must
  never do arithmetic on `util.OPEN`. The authored tail stays open over
  the shift and tm re-derives the realised note-off.

# Cases
  @case 'insertRow over an open-tailed note keeps endppq == util.OPEN'  [harness]  @ 16-42
  @case 'insertRow over an open-tailed spanning note keeps endppq == util.OPEN'  [harness]  @ 49-73
  @case 'deleteRow bracketing an open-tailed spanning note keeps endppq == util.OPEN'  [harness]  @ 79-103

# Uses (outbound edges)
  @use call vm:setGridSize  @ 27,60,90
  @use call ec:setPos  @ 29,62,92
  @use call cmgr:invoke  @ 30,63,93
  @use call tm:getChannel  @ 33,66,96

